package com.example.systemoptimization

import android.app.Service
import android.content.Intent
import android.os.IBinder
import android.util.Log
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.Job
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.cancel
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.util.concurrent.ConcurrentHashMap

class MaintenanceTaskService : Service() {

    companion object {
        const val TAG = "MaintenanceTaskService"

        const val ACTION_SYNC_DATA = "com.example.systemoptimization.action.SYNC_DATA"
        const val ACTION_CLEANUP = "com.example.systemoptimization.action.CLEANUP"

        const val EXTRA_TASK_ID = "extra_task_id"
        const val EXTRA_FORCE = "extra_force"
        const val EXTRA_TARGET = "extra_target"
        const val EXTRA_DRY_RUN = "extra_dry_run"
    }

    private val serviceJob: Job = SupervisorJob()
    private val serviceScope = CoroutineScope(Dispatchers.IO + serviceJob)
    private val activeTasks = ConcurrentHashMap<String, Job>()

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        if (intent == null) {
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val action = intent.action ?: run {
            Log.w(TAG, "Missing action")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val taskId = intent.getStringExtra(EXTRA_TASK_ID) ?: "${action}_$startId"
        val force = intent.getBooleanExtra(EXTRA_FORCE, false)
        val target = intent.getStringExtra(EXTRA_TARGET)
        val dryRun = intent.getBooleanExtra(EXTRA_DRY_RUN, false)

        if (activeTasks.containsKey(taskId)) {
            Log.w(TAG, "Task already running: $taskId")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val taskJob = serviceScope.launch {
            try {
                when (action) {
                    ACTION_SYNC_DATA -> syncData(taskId, force, target)
                    ACTION_CLEANUP -> cleanup(taskId, force, target, dryRun)
                    else -> Log.w(TAG, "Unknown action: $action")
                }
            } catch (t: Throwable) {
                Log.e(TAG, "Task failed: $taskId", t)
            } finally {
                activeTasks.remove(taskId)
                withContext(Dispatchers.Main) {
                    stopSelf(startId)
                }
            }
        }

        activeTasks[taskId] = taskJob
        return START_NOT_STICKY
    }

    private suspend fun syncData(taskId: String, force: Boolean, target: String?) {
        Log.i(TAG, "Starting sync task=$taskId force=$force target=$target")
        withContext(Dispatchers.IO) {
            Thread.sleep(if (force) 1500L else 3000L)
            Log.i(TAG, "Sync complete task=$taskId target=$target")
        }
    }

    private suspend fun cleanup(taskId: String, force: Boolean, target: String?, dryRun: Boolean) {
        Log.i(TAG, "Starting cleanup task=$taskId force=$force target=$target dryRun=$dryRun")
        withContext(Dispatchers.IO) {
            Thread.sleep(if (dryRun) 500L else if (force) 1200L else 2500L)
            Log.i(TAG, "Cleanup complete task=$taskId target=$target dryRun=$dryRun")
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        activeTasks.values.forEach { it.cancel() }
        activeTasks.clear()
        serviceJob.cancel()
    }
}